SELECT id, family_id, user_id, balance, created_at, updated_at
FROM point_accounts
WHERE id = #{id, jdbcType=OTHER, typeHandler=com.kidspoint.api.config.UUIDTypeHandler}

SELECT id, family_id, user_id, balance, created_at, updated_at
FROM point_accounts
WHERE family_id = #{familyId, jdbcType=OTHER, typeHandler=com.kidspoint.api.config.UUIDTypeHandler}
  AND user_id = #{userId, jdbcType=OTHER, typeHandler=com.kidspoint.api.config.UUIDTypeHandler}

mapper.update:
UPDATE point_accounts
SET balance = #{balance},
    updated_at = #{updatedAt}
WHERE id = #{id, jdbcType=OTHER, typeHandler=com.kidspoint.api.config.UUIDTypeHandler}
